const PROCESSING_FEE = 5;
const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; material: string; enchantment: number; cursed: boolean };

const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_ITEM_TYPE[item.type];

const runeBaseFor = (runeCount: number): number =>
  runeCount === RUNE_BLOCK_SIZE
    ? RUNE_BLOCK_PRICE
    : runeCount * BASE_PREMIUM_BY_ITEM_TYPE.rune;

export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
  const runeCount = input.items.filter((item) => item.type === "rune").length;
  const nonRuneItemsBase = input.items
    .filter((item) => item.type !== "rune")
    .reduce((sum, item) => sum + basePremiumFor(item), 0);
  return nonRuneItemsBase + runeBaseFor(runeCount) + PROCESSING_FEE;
}

input.new_string:
const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;
const MOONSTONE_BLOCK_PRICE = 60;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; material: string; enchantment: number; cursed: boolean };

const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_ITEM_TYPE[item.type];

const runeBaseFor = (runeCount: number): number =>
  runeCount === BLOCK_SIZE
    ? RUNE_BLOCK_PRICE
    : runeCount * BASE_PREMIUM_BY_ITEM_TYPE.rune;

const moonstoneBaseFor = (moonstoneCount: number): number =>
  moonstoneCount === BLOCK_SIZE
    ? MOONSTONE_BLOCK_PRICE
    : moonstoneCount * BASE_PREMIUM_BY_ITEM_TYPE.moonstone;

export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
  const runeCount = input.items.filter((item) => item.type === "rune").length;
  const moonstoneCount = input.items.filter((item) => item.type === "moonstone").length;
  const otherItemsBase = input.items
    .filter((item) => item.type !== "rune" && item.type !== "moonstone")
    .reduce((sum, item) => sum + basePremiumFor(item), 0);
  return otherItemsBase + runeBaseFor(runeCount) + moonstoneBaseFor(moonstoneCount) + PROCESSING_FEE;
}
